# Class Definition in JavaScript

```javascript
class Vehicle {
    constructor(brand, model) {
        this.brand = brand;
        this.model = model;
    }
}

// Instantiation
const myCar = new Vehicle('Toyota', 'Corolla');
console.log(myCar);
```

# Class Inheritance in JavaScript

```javascript
class Car extends Vehicle {
    constructor(brand, model, year) {
        super(brand, model);
        this.year = year;
    }
}

// Usage
const myCar = new Car('Honda', 'Accord', 2020);
console.log(myCar);
```

# Class Methods and Properties

```javascript
class Rectangle {
    constructor(width, height) {
        this.width = width;
        this.height = height;
    }

    // Static method
    static description() {
        return 'Rectangles have four sides and four right angles.';
    }

    // Getter
    get area() {
        return this.width * this.height;
    }
}

// Usage
const myRectangle = new Rectangle(7, 5);
console.log(Rectangle.description());
console.log(myRectangle.area);
```
